<style scoped>
.countries path,
.country {
  cursor: pointer;
  transition: fill 0.2s ease;
}

.countries path:hover {
  fill: var(--title-color);
}

.country:hover path {
  fill: var(--title-color) !important;
}

@keyframes pulse {
  0% {
    filter: drop-shadow(0 0 0 rgba(0, 0, 0, 0.7));
  }
  100% {
    filter: drop-shadow(0 0 10px rgba(0, 0, 0, 0));
  }
}
</style>

<script>
export default {
  name: "EuropeMap",
  props: {
    onClick: {
      type: Function,
      default: null,
    },
  },
  methods: {
    click(event) {
      if (event.target.matches("path")) {
        let path = event.target;
        let country = path.getAttribute("id");
        while (!country && path.parentElement) {
          const parent = path.parentElement;
          if (!parent) return;
          country = parent.getAttribute("id");
          path = parent;
        }
        if (this.onClick && country) {
          this.onClick(country);
        }
      }
    },
  },
};
</script>
